ON CONFLICT (rule_number) DO UPDATE SET
  species_scope = EXCLUDED.species_scope,
  max_perc_feed = EXCLUDED.max_perc_feed,
  max_perc_conc = EXCLUDED.max_perc_conc,
  max_perc_weight = EXCLUDED.max_perc_weight,
  max_feed_weight_kg = EXCLUDED.max_feed_weight_kg,
  production_focus = EXCLUDED.production_focus,
  sex_restriction = EXCLUDED.sex_restriction,
  min_age_months = EXCLUDED.min_age_months,
  max_age_months = EXCLUDED.max_age_months,
  breeding_cycle = EXCLUDED.breeding_cycle,
  lactation_exclusion = EXCLUDED.lactation_exclusion,
  lactation_inclusion = EXCLUDED.lactation_inclusion,
  dietary_needs = EXCLUDED.dietary_needs,
  is_active = EXCLUDED.is_active,
  product_id = EXCLUDED.product_id;

INSERT INTO feed_product_trans (product_id, locale, name)
SELECT id, 'en', name_en
FROM feed_products
WHERE product_number BETWEEN 1009 AND 1007
ON CONFLICT (product_id, locale) DO UPDATE
  SET name = EXCLUDED.name;

INSERT INTO feed_product_trans (product_id, locale, name)
SELECT id, 'ar', name_ar
FROM feed_products
WHERE product_number BETWEEN 1009 AND 1007
  AND name_ar IS NOT NULL
ON CONFLICT (product_id, locale) DO UPDATE
  SET name = EXCLUDED.name;

COMMIT;
